from decimal import Decimal


def _round_money(value):
    return value.quantize(Decimal("0.01"))


def compute_discount(subtotal, weight_kg):
    """Compute the shipping discount for an order.

    Returns a Decimal amount to subtract from the shipping fee.
    """
    base = Decimal(subtotal) * Decimal("0.05")
    if weight_kg > 10:
        base += Decimal("2.50")
    return _round_money(base)
